// HasPlugins applies the HasEdge predicate on the "plugins" edge.
func HasPlugins() predicate.AgentPluginRepo {
	return predicate.AgentPluginRepo(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, PluginsTable, PluginsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasPluginsWith applies the HasEdge predicate on the "plugins" edge with a given conditions (other predicates).
func HasPluginsWith(preds ...predicate.AgentPlugin) predicate.AgentPluginRepo {
	return predicate.AgentPluginRepo(func(s *sql.Selector) {
		step := newPluginsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.AgentPluginRepo) predicate.AgentPluginRepo {
	return predicate.AgentPluginRepo(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AgentPluginRepo) predicate.AgentPluginRepo {
	return predicate.AgentPluginRepo(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AgentPluginRepo) predicate.AgentPluginRepo {
	return predicate.AgentPluginRepo(sql.NotPredicates(p))
}
